/**
 * Headless Defer Hook — PreToolUse permission deferral for -p mode
 *
 * CC 2.1.89: PreToolUse hooks can return {decision:"defer"} to pause
 * headless sessions. The session saves state and can resume with --resume,
 * at which point this hook re-evaluates.
 *
 * Use case: CI pipelines that need human approval for destructive ops
 * (e.g., database migrations, production deploys, force pushes).
 *
 * Only fires when CLAUDE_HEADLESS=1 (set by -p mode).
 * Configurable via ORCHESTKIT_DEFER_TOOLS env var (comma-separated tool patterns).
 *
 * @hook PreToolUse
 * @since CC 2.1.89
 * @see #1222
 */

import type { HookInput, HookResult } from '../types.js';
import { outputSilentSuccess, outputDefer, logHook } from '../lib/common.js';

const HOOK_NAME = 'headless-defer';

/**
 * Default tools that require human approval in headless mode.
 * Override with ORCHESTKIT_DEFER_TOOLS="Bash(git push *),Bash(npm publish *)"
 */
const DEFAULT_DEFER_PATTERNS = [
  'Bash(git push --force*)',
  'Bash(git push -f*)',
  'Bash(npm publish*)',
  'Bash(npx wrangler deploy*)',
  'Bash(terraform apply*)',
  'Bash(kubectl apply*)',
  'Bash(kubectl delete*)',
  'Bash(docker push*)',
  'Bash(alembic upgrade head*)',
  'Bash(gh pr merge*)',
  'Bash(gh release create*)',
];

function getDeferPatterns(): string[] {
  const envPatterns = process.env.ORCHESTKIT_DEFER_TOOLS;
  if (envPatterns) {
    return envPatterns.split(',').map(p => p.trim()).filter(Boolean);
  }
  return DEFAULT_DEFER_PATTERNS;
}

/**
 * Match a tool invocation against defer patterns.
 * Patterns use simple glob: * matches any substring.
 */
function matchesPattern(toolName: string, command: string, pattern: string): boolean {
  // Pattern format: ToolName(glob) or just ToolName
  const parenIdx = pattern.indexOf('(');
  if (parenIdx === -1) {
    return toolName === pattern;
  }

  const patternTool = pattern.slice(0, parenIdx);
  if (toolName !== patternTool) return false;

  const patternGlob = pattern.slice(parenIdx + 1, -1); // strip parens
  // Convert glob to regex: escape special chars, replace * with .*
  const regex = new RegExp(
    `^${patternGlob.replace(/[.+?^${}()|[\]\\]/g, '\\$&').replace(/\*/g, '.*')}$`
  );
  return regex.test(command);
}

export function headlessDefer(input: HookInput): HookResult {
  // Only active in headless -p mode
  if (!process.env.CLAUDE_HEADLESS && !process.env.CLAUDE_NONINTERACTIVE) {
    return outputSilentSuccess();
  }

  const toolName = input.tool_name || '';
  const command = input.tool_input?.command || '';
  const patterns = getDeferPatterns();

  for (const pattern of patterns) {
    if (matchesPattern(toolName, command, pattern)) {
      const reason = `Deferred for human approval: ${toolName}(${command.slice(0, 80)})`;
      logHook(HOOK_NAME, reason);
      return outputDefer(reason);
    }
  }

  return outputSilentSuccess();
}
